VALUES
  ('heelevel3-7c4986e7-moex-00125', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'single_choice', 'A 公司購買了一個新型螢幕用以展示產品，此螢幕的售價為 50,000 元，而該機型的折舊率為每年 25%。假設A公司向銀行借貸的利率為10%、存款利率為6%、預期通貨膨脹率為5%。若A公司利 用自有資金購買此螢幕設備，則A公司第一年的廠商使用資本成本（usercostofcapital）為何？', '["12,500元", "13,000元", "15,000元", "12,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
